const rssData = $node["2. Get Latest News"].json.data;
const titles = rssData.match(/<title>(.*?)<\/title>/g) || [];
const links = rssData.match(/<link>(.*?)<\/link>/g) || [];
const newsList = [];

for (let i = 1; i < Math.min(titles.length, 11); i++) {
  const cleanTitle = titles[i].replace(/<\/?title>/g, '');
  const cleanLink = links[i].replace(/<\/?link>/g, '');
  newsList.push(`Title: ${cleanTitle} \nURL: ${cleanLink}`);
}

return {
  newsDataForAI: newsList.join('\n---\n')
};

